import{_ as o,c as a,o as t,aj as r}from"./chunks/framework.BlveriQe.js";const p=JSON.parse('{"title":"Interface: CollectionsAPI","description":"","frontmatter":{},"headers":[],"relativePath":"reference/js-bao-wss-client/api/interfaces/CollectionsAPI.md","filePath":"reference/js-bao-wss-client/api/interfaces/CollectionsAPI.md"}'),c={name:"reference/js-bao-wss-client/api/interfaces/CollectionsAPI.md"};function i(n,e,l,d,s,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<p><a href="./../README.html"><strong>js-bao-wss-client</strong></a></p><hr><p><a href="./../globals.html">js-bao-wss-client</a> / CollectionsAPI</p><h1 id="interface-collectionsapi" tabindex="-1">Interface: CollectionsAPI <a class="header-anchor" href="#interface-collectionsapi" aria-label="Permalink to “Interface: CollectionsAPI”">​</a></h1><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to “Methods”">​</a></h2><h3 id="adddocument" tabindex="-1">addDocument() <a class="header-anchor" href="#adddocument" aria-label="Permalink to “addDocument()”">​</a></h3><blockquote><p><strong>addDocument</strong>(<code>collectionId</code>, <code>documentId</code>): <code>Promise</code>&lt;<a href="./CollectionDocumentInfo.html"><code>CollectionDocumentInfo</code></a>&gt;</p></blockquote><p>Add a document to a collection.</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="collectionid" tabindex="-1">collectionId <a class="header-anchor" href="#collectionid" aria-label="Permalink to “collectionId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the collection to add the document to</p><h5 id="documentid" tabindex="-1">documentId <a class="header-anchor" href="#documentid" aria-label="Permalink to “documentId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the document to add</p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./CollectionDocumentInfo.html"><code>CollectionDocumentInfo</code></a>&gt;</p><hr><h3 id="addmember" tabindex="-1">addMember() <a class="header-anchor" href="#addmember" aria-label="Permalink to “addMember()”">​</a></h3><blockquote><p><strong>addMember</strong>(<code>collectionId</code>, <code>params</code>): <code>Promise</code>&lt;<a href="./../type-aliases/CollectionAddMemberResult.html"><code>CollectionAddMemberResult</code></a>&gt;</p></blockquote><p>Add a member to a collection by user ID or email address.</p><p>Returns a discriminated union based on whether the target is an existing app user (direct add) or a yet-to-sign-up email (deferred add):</p><ul><li><code>{ status: &quot;added&quot;, userId, permission, addedAt, addedBy, ... }</code> — new membership created.</li><li><code>{ status: &quot;already_member&quot;, userId, permission, ... }</code> — the user already had the requested permission.</li><li><code>{ status: &quot;pending_signup&quot;, email, permission, deferredId, expiresAt, invitationId, inviteToken }</code> — email not yet in the app; a <code>DeferredGroupAdd</code> row has been created (or an existing unresolved one is returned idempotently). When the recipient signs in, the grant resolves into the same access state a direct add would have produced.</li></ul><h4 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="collectionid-1" tabindex="-1">collectionId <a class="header-anchor" href="#collectionid-1" aria-label="Permalink to “collectionId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the collection to add the member to</p><h5 id="params" tabindex="-1">params <a class="header-anchor" href="#params" aria-label="Permalink to “params”">​</a></h5><p><a href="./../type-aliases/AddCollectionMemberParams.html"><code>AddCollectionMemberParams</code></a></p><p>Member details (provide either userId or email, not both)</p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./../type-aliases/CollectionAddMemberResult.html"><code>CollectionAddMemberResult</code></a>&gt;</p><hr><h3 id="create" tabindex="-1">create() <a class="header-anchor" href="#create" aria-label="Permalink to “create()”">​</a></h3><blockquote><p><strong>create</strong>(<code>params</code>): <code>Promise</code>&lt;<a href="./CollectionInfo.html"><code>CollectionInfo</code></a>&gt;</p></blockquote><p>Create a new collection.</p><h4 id="parameters-2" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-2" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="params-1" tabindex="-1">params <a class="header-anchor" href="#params-1" aria-label="Permalink to “params”">​</a></h5><p><code>CreateCollectionParams</code></p><p>Configuration for the new collection</p><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./CollectionInfo.html"><code>CollectionInfo</code></a>&gt;</p><hr><h3 id="delete" tabindex="-1">delete() <a class="header-anchor" href="#delete" aria-label="Permalink to “delete()”">​</a></h3><blockquote><p><strong>delete</strong>(<code>collectionId</code>): <code>Promise</code>&lt;{ <code>success</code>: <code>boolean</code>; }&gt;</p></blockquote><p>Delete a collection.</p><h4 id="parameters-3" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-3" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="collectionid-2" tabindex="-1">collectionId <a class="header-anchor" href="#collectionid-2" aria-label="Permalink to “collectionId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the collection to delete</p><h4 id="returns-3" tabindex="-1">Returns <a class="header-anchor" href="#returns-3" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;{ <code>success</code>: <code>boolean</code>; }&gt;</p><hr><h3 id="get" tabindex="-1">get() <a class="header-anchor" href="#get" aria-label="Permalink to “get()”">​</a></h3><blockquote><p><strong>get</strong>(<code>collectionId</code>): <code>Promise</code>&lt;<a href="./CollectionInfo.html"><code>CollectionInfo</code></a>&gt;</p></blockquote><p>Get collection info by ID.</p><p>Callers must either be an admin/owner of the app, hold a direct <code>_col-reader</code> or <code>_col-writer</code> membership on the collection, or belong to a user-group that has been granted a <code>CollectionGroupPermission</code> of <code>reader</code> or <code>read-write</code>. Otherwise the server returns 404 (to avoid leaking collection existence).</p><h4 id="parameters-4" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-4" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="collectionid-3" tabindex="-1">collectionId <a class="header-anchor" href="#collectionid-3" aria-label="Permalink to “collectionId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the collection to retrieve</p><h4 id="returns-4" tabindex="-1">Returns <a class="header-anchor" href="#returns-4" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./CollectionInfo.html"><code>CollectionInfo</code></a>&gt;</p><hr><h3 id="getaccess" tabindex="-1">getAccess() <a class="header-anchor" href="#getaccess" aria-label="Permalink to “getAccess()”">​</a></h3><blockquote><p><strong>getAccess</strong>(<code>collectionId</code>): <code>Promise</code>&lt;<a href="./CollectionAccessInfo.html"><code>CollectionAccessInfo</code></a>&gt;</p></blockquote><p>Get the current user&#39;s access info for a collection.</p><h4 id="parameters-5" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-5" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="collectionid-4" tabindex="-1">collectionId <a class="header-anchor" href="#collectionid-4" aria-label="Permalink to “collectionId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the collection to check access for</p><h4 id="returns-5" tabindex="-1">Returns <a class="header-anchor" href="#returns-5" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./CollectionAccessInfo.html"><code>CollectionAccessInfo</code></a>&gt;</p><hr><h3 id="grantgrouppermission" tabindex="-1">grantGroupPermission() <a class="header-anchor" href="#grantgrouppermission" aria-label="Permalink to “grantGroupPermission()”">​</a></h3><blockquote><p><strong>grantGroupPermission</strong>(<code>collectionId</code>, <code>params</code>): <code>Promise</code>&lt;<a href="./CollectionGroupPermissionInfo.html"><code>CollectionGroupPermissionInfo</code></a>&gt;</p></blockquote><p>Grant a group permission to a collection.</p><h4 id="parameters-6" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-6" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="collectionid-5" tabindex="-1">collectionId <a class="header-anchor" href="#collectionid-5" aria-label="Permalink to “collectionId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the collection to grant access to</p><h5 id="params-2" tabindex="-1">params <a class="header-anchor" href="#params-2" aria-label="Permalink to “params”">​</a></h5><p><code>GrantCollectionGroupPermissionParams</code></p><p>Permission grant details</p><h4 id="returns-6" tabindex="-1">Returns <a class="header-anchor" href="#returns-6" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./CollectionGroupPermissionInfo.html"><code>CollectionGroupPermissionInfo</code></a>&gt;</p><hr><h3 id="list" tabindex="-1">list() <a class="header-anchor" href="#list" aria-label="Permalink to “list()”">​</a></h3><blockquote><p><strong>list</strong>(<code>options?</code>): <code>Promise</code>&lt;<code>PaginatedResult</code>&lt;<a href="./CollectionInfo.html"><code>CollectionInfo</code></a>&gt;&gt;</p></blockquote><p>List collections the caller is a direct member of (reader or read-write).</p><p>This returns only collections the caller has been explicitly added to — it does NOT include collections accessible only via a user-created group that holds a <code>CollectionGroupPermission</code>. Admins see only their own direct memberships too; use <code>listAll()</code> for the full app-wide set.</p><p>Each returned item includes a <code>permission</code> field (<code>&quot;reader&quot;</code> or <code>&quot;read-write&quot;</code>) reflecting the caller&#39;s direct access level.</p><h4 id="parameters-7" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-7" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options" tabindex="-1">options? <a class="header-anchor" href="#options" aria-label="Permalink to “options?”">​</a></h5><p><code>PaginationOptions</code></p><p>Pagination controls</p><h4 id="returns-7" tabindex="-1">Returns <a class="header-anchor" href="#returns-7" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<code>PaginatedResult</code>&lt;<a href="./CollectionInfo.html"><code>CollectionInfo</code></a>&gt;&gt;</p><hr><h3 id="listall" tabindex="-1">listAll() <a class="header-anchor" href="#listall" aria-label="Permalink to “listAll()”">​</a></h3><blockquote><p><strong>listAll</strong>(<code>options?</code>): <code>Promise</code>&lt;<code>PaginatedResult</code>&lt;<a href="./CollectionInfo.html"><code>CollectionInfo</code></a>&gt;&gt;</p></blockquote><p>List every collection in the app (admin-only).</p><p>Non-admin callers receive a 403. Unlike <code>list()</code>, the returned items do not include a <code>permission</code> field (since the caller may not have direct access to many of them).</p><h4 id="parameters-8" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-8" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options-1" tabindex="-1">options? <a class="header-anchor" href="#options-1" aria-label="Permalink to “options?”">​</a></h5><p><code>PaginationOptions</code></p><p>Pagination controls</p><h4 id="returns-8" tabindex="-1">Returns <a class="header-anchor" href="#returns-8" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<code>PaginatedResult</code>&lt;<a href="./CollectionInfo.html"><code>CollectionInfo</code></a>&gt;&gt;</p><hr><h3 id="listcollectionsfordocument" tabindex="-1">listCollectionsForDocument() <a class="header-anchor" href="#listcollectionsfordocument" aria-label="Permalink to “listCollectionsForDocument()”">​</a></h3><blockquote><p><strong>listCollectionsForDocument</strong>(<code>documentId</code>, <code>options?</code>): <code>Promise</code>&lt;<code>PaginatedResult</code>&lt;<a href="./DocumentCollectionInfo.html"><code>DocumentCollectionInfo</code></a>&gt;&gt;</p></blockquote><p>List collections that contain a specific document.</p><p>For admin/owner callers, returns every collection the document belongs to. For non-admin callers, returns only collections the caller is a direct member of (<code>_col-reader</code> or <code>_col-writer</code>). Access via a user-created group is NOT counted here (consistent with <code>list()</code>).</p><h4 id="parameters-9" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-9" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="documentid-1" tabindex="-1">documentId <a class="header-anchor" href="#documentid-1" aria-label="Permalink to “documentId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the document to look up</p><h5 id="options-2" tabindex="-1">options? <a class="header-anchor" href="#options-2" aria-label="Permalink to “options?”">​</a></h5><p><code>PaginationOptions</code></p><p>Pagination controls</p><h4 id="returns-9" tabindex="-1">Returns <a class="header-anchor" href="#returns-9" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<code>PaginatedResult</code>&lt;<a href="./DocumentCollectionInfo.html"><code>DocumentCollectionInfo</code></a>&gt;&gt;</p><hr><h3 id="listdocuments" tabindex="-1">listDocuments() <a class="header-anchor" href="#listdocuments" aria-label="Permalink to “listDocuments()”">​</a></h3><blockquote><p><strong>listDocuments</strong>(<code>collectionId</code>, <code>options?</code>): <code>Promise</code>&lt;<code>PaginatedResult</code>&lt;<a href="./CollectionDocumentInfo.html"><code>CollectionDocumentInfo</code></a>&gt;&gt;</p></blockquote><p>List all documents in a collection.</p><h4 id="parameters-10" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-10" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="collectionid-6" tabindex="-1">collectionId <a class="header-anchor" href="#collectionid-6" aria-label="Permalink to “collectionId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the collection whose documents to list</p><h5 id="options-3" tabindex="-1">options? <a class="header-anchor" href="#options-3" aria-label="Permalink to “options?”">​</a></h5><p><code>PaginationOptions</code></p><p>Pagination controls</p><h4 id="returns-10" tabindex="-1">Returns <a class="header-anchor" href="#returns-10" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<code>PaginatedResult</code>&lt;<a href="./CollectionDocumentInfo.html"><code>CollectionDocumentInfo</code></a>&gt;&gt;</p><hr><h3 id="listpendinginvitations" tabindex="-1">listPendingInvitations() <a class="header-anchor" href="#listpendinginvitations" aria-label="Permalink to “listPendingInvitations()”">​</a></h3><blockquote><p><strong>listPendingInvitations</strong>(<code>collectionId</code>): <code>Promise</code>&lt;<a href="./PendingCollectionInvitationEntry.html"><code>PendingCollectionInvitationEntry</code></a>[]&gt;</p></blockquote><p>Lists pending (unresolved, non-expired) invitations scoped to a collection. Returns denormalized rows so callers can render a &quot;members</p><ul><li>pending&quot; view without touching the internal deferred-grants surface.</li></ul><p>Visibility: callers with any read access to the collection can see this list — direct <code>_col-*</code> members, indirect members via a user-defined group with a <code>CollectionGroupPermission</code>, and app admins/owners.</p><h4 id="parameters-11" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-11" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="collectionid-7" tabindex="-1">collectionId <a class="header-anchor" href="#collectionid-7" aria-label="Permalink to “collectionId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the collection</p><h4 id="returns-11" tabindex="-1">Returns <a class="header-anchor" href="#returns-11" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./PendingCollectionInvitationEntry.html"><code>PendingCollectionInvitationEntry</code></a>[]&gt;</p><hr><h3 id="removedocument" tabindex="-1">removeDocument() <a class="header-anchor" href="#removedocument" aria-label="Permalink to “removeDocument()”">​</a></h3><blockquote><p><strong>removeDocument</strong>(<code>collectionId</code>, <code>documentId</code>): <code>Promise</code>&lt;{ <code>success</code>: <code>boolean</code>; }&gt;</p></blockquote><p>Remove a document from a collection.</p><h4 id="parameters-12" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-12" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="collectionid-8" tabindex="-1">collectionId <a class="header-anchor" href="#collectionid-8" aria-label="Permalink to “collectionId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the collection to remove the document from</p><h5 id="documentid-2" tabindex="-1">documentId <a class="header-anchor" href="#documentid-2" aria-label="Permalink to “documentId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the document to remove</p><h4 id="returns-12" tabindex="-1">Returns <a class="header-anchor" href="#returns-12" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;{ <code>success</code>: <code>boolean</code>; }&gt;</p><hr><h3 id="removemember" tabindex="-1">removeMember() <a class="header-anchor" href="#removemember" aria-label="Permalink to “removeMember()”">​</a></h3><blockquote><p><strong>removeMember</strong>(<code>collectionId</code>, <code>userId</code>): <code>Promise</code>&lt;{ <code>success</code>: <code>boolean</code>; }&gt;</p></blockquote><p>Remove a member from a collection.</p><h4 id="parameters-13" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-13" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="collectionid-9" tabindex="-1">collectionId <a class="header-anchor" href="#collectionid-9" aria-label="Permalink to “collectionId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the collection to remove the member from</p><h5 id="userid" tabindex="-1">userId <a class="header-anchor" href="#userid" aria-label="Permalink to “userId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the user to remove</p><h4 id="returns-13" tabindex="-1">Returns <a class="header-anchor" href="#returns-13" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;{ <code>success</code>: <code>boolean</code>; }&gt;</p><hr><h3 id="revokegrouppermission" tabindex="-1">revokeGroupPermission() <a class="header-anchor" href="#revokegrouppermission" aria-label="Permalink to “revokeGroupPermission()”">​</a></h3><blockquote><p><strong>revokeGroupPermission</strong>(<code>collectionId</code>, <code>groupType</code>, <code>groupId</code>): <code>Promise</code>&lt;{ <code>success</code>: <code>boolean</code>; }&gt;</p></blockquote><p>Revoke a group&#39;s permission from a collection.</p><h4 id="parameters-14" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-14" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="collectionid-10" tabindex="-1">collectionId <a class="header-anchor" href="#collectionid-10" aria-label="Permalink to “collectionId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the collection to revoke access from</p><h5 id="grouptype" tabindex="-1">groupType <a class="header-anchor" href="#grouptype" aria-label="Permalink to “groupType”">​</a></h5><p><code>string</code></p><p>The kind of group whose permission is being revoked</p><h5 id="groupid" tabindex="-1">groupId <a class="header-anchor" href="#groupid" aria-label="Permalink to “groupId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the group losing the permission</p><h4 id="returns-14" tabindex="-1">Returns <a class="header-anchor" href="#returns-14" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;{ <code>success</code>: <code>boolean</code>; }&gt;</p><hr><h3 id="update" tabindex="-1">update() <a class="header-anchor" href="#update" aria-label="Permalink to “update()”">​</a></h3><blockquote><p><strong>update</strong>(<code>collectionId</code>, <code>params</code>): <code>Promise</code>&lt;<a href="./CollectionInfo.html"><code>CollectionInfo</code></a>&gt;</p></blockquote><p>Update a collection&#39;s title or description.</p><h4 id="parameters-15" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-15" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="collectionid-11" tabindex="-1">collectionId <a class="header-anchor" href="#collectionid-11" aria-label="Permalink to “collectionId”">​</a></h5><p><code>string</code></p><p>The unique identifier of the collection to update</p><h5 id="params-3" tabindex="-1">params <a class="header-anchor" href="#params-3" aria-label="Permalink to “params”">​</a></h5><p><code>UpdateCollectionParams</code></p><p>Fields to update on the collection</p><h4 id="returns-15" tabindex="-1">Returns <a class="header-anchor" href="#returns-15" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./CollectionInfo.html"><code>CollectionInfo</code></a>&gt;</p>',203)])])}const u=o(c,[["render",i]]);export{p as __pageData,u as default};
